/**
 * @summary List content pieces
 */
export const getListContentPiecesUrl = (params?: ListContentPiecesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/content-pieces?${stringifiedParams}`
    : `/api/content-pieces`;
};

export const listContentPieces = async (
  params?: ListContentPiecesParams,
  options?: RequestInit,
): Promise<ContentPiece[]> => {
  return customFetch<ContentPiece[]>(getListContentPiecesUrl(params), {
    ...options,
    method: "GET",
  });
};

